#!/usr/bin/env node
/**
 * Generates the project and theme registries used by the static site.
 *
 * The browser never scans the content or shader folders at runtime. This
 * script performs the discovery step ahead of time and writes deterministic
 * generated JavaScript modules that the site imports.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const GENERATED_HEADER =
  "// This file is generated by scripts/generate-content-index.mjs.\n" +
  "// Do not edit manually.";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const projectContentDir = path.join(repoRoot, "content", "projects");
const themeSourceDir = path.join(repoRoot, "js", "themes");
const generatedProjectIndexPath = path.join(
  repoRoot,
  "js",
  "projects",
  "ProjectIndex.generated.js",
);
const generatedThemeRegistryPath = path.join(
  repoRoot,
  "js",
  "background",
  "ThemeRegistry.generated.js",
);

main().catch((error) => {
  console.error(error instanceof Error ? error.message : error);
  process.exitCode = 1;
});

async function main() {
  const projects = readProjectMarkdownFiles(projectContentDir);
  const themes = readThemeModules(themeSourceDir);

  writeFileIfChanged(generatedProjectIndexPath, serializeProjectIndex(projects));
  writeFileIfChanged(generatedThemeRegistryPath, serializeThemeRegistry(themes));

  console.log(`Generated ${projects.length} project registry entr${projects.length === 1 ? "y" : "ies"} and ${themes.length} theme entr${themes.length === 1 ? "y" : "ies"}.`);
}

/**
 * Reads and normalizes all project markdown files.
 * @param {string} contentDir
 * @returns {Array<{
 *   slug: string,
 *   title: string,
 *   summary: string,
 *   date: string,
 *   type: string,
 *   thumbnail: string,
 *   heroImage: string,
 *   heroAlt: string,
 *   tags: string[],
 *   markdownPath: string,
 * }>}
 */
function readProjectMarkdownFiles(contentDir) {
  if (!fs.existsSync(contentDir)) {
    throw new Error(`Project content directory not found: ${contentDir}`);
  }

  const markdownFiles = fs
    .readdirSync(contentDir)
    .filter((fileName) => fileName.endsWith(".md"))
    .sort((left, right) => left.localeCompare(right, "en"));

  if (markdownFiles.length === 0) {
    throw new Error(`No markdown project files found in ${contentDir}`);
  }

  const projects = markdownFiles.map((fileName) => {
    const filePath = path.join(contentDir, fileName);
    const source = fs.readFileSync(filePath, "utf8");
    const { frontMatter } = parseFrontMatter(source);
    const slug = readRequiredString(frontMatter.slug, filePath, "slug");
    const title = readRequiredString(frontMatter.title, filePath, "title");
    const summary = readRequiredString(frontMatter.summary, filePath, "summary");
    const date = readOptionalString(frontMatter.date);
    const type = readOptionalString(frontMatter.type);
    const thumbnail = readOptionalString(frontMatter.thumbnail);
    const heroImage = readOptionalString(frontMatter.heroImage);
    const heroAlt = readOptionalString(frontMatter.heroAlt);
    const tags = readStringArray(frontMatter.tags);

    return {
      slug,
      title,
      summary,
      date,
      type,
      thumbnail,
      heroImage,
      heroAlt,
      tags,
      markdownPath: toPosix(path.relative(repoRoot, filePath)),
    };
  });

  projects.sort((left, right) => {
    const slugComparison = left.slug.localeCompare(right.slug, "en", {
      sensitivity: "base",
      numeric: true,
    });
    if (slugComparison !== 0) {
      return slugComparison;
    }

    return left.markdownPath.localeCompare(right.markdownPath, "en", {
      sensitivity: "base",
      numeric: true,
    });
  });

  assertNoDuplicateValues(projects.map((project) => project.slug), "project slug");
  return projects;
}

/**
 * Reads and validates all shader theme modules.
 * @param {string} sourceDir
 * @returns {Array<{
 *   fileName: string,
 *   filePath: string,
 *   importBase: string,
 *   meta: {id: string, label: string, order: number},
 * }>}
 */
function readThemeModules(sourceDir) {
  if (!fs.existsSync(sourceDir)) {
    throw new Error(`Theme source directory not found: ${sourceDir}`);
  }

  const themeFiles = fs
    .readdirSync(sourceDir)
    .filter((fileName) => fileName.endsWith(".js"))
    .sort((left, right) => left.localeCompare(right, "en"));

  if (themeFiles.length === 0) {
    throw new Error(`No theme modules found in ${sourceDir}`);
  }

  const themes = themeFiles.map((fileName) => {
    const filePath = path.join(sourceDir, fileName);
    const source = fs.readFileSync(filePath, "utf8");

    if (!/export\s+const\s+themeMeta\s*=/.test(source)) {
      throw new Error(`Theme module is missing export const themeMeta: ${filePath}`);
    }

    if (!/export\s+function\s+createTheme\s*\(/.test(source)) {
      throw new Error(`Theme module is missing export function createTheme: ${filePath}`);
    }

    return {
      fileName,
      filePath,
      importBase: toIdentifierBase(path.basename(fileName, ".js")),
      meta: extractThemeMeta(source, filePath),
    };
  });

  themes.sort((left, right) => {
    const orderComparison = (left.meta.order || 0) - (right.meta.order || 0);
    if (orderComparison !== 0) {
      return orderComparison;
    }

    const labelComparison = left.meta.label.localeCompare(right.meta.label, "en", {
      sensitivity: "base",
      numeric: true,
    });
    if (labelComparison !== 0) {
      return labelComparison;
    }

    return left.meta.id.localeCompare(right.meta.id, "en", {
      sensitivity: "base",
      numeric: true,
    });
  });

  assertNoDuplicateValues(themes.map((theme) => theme.meta.id), "theme id");
  return themes;
}

/**
 * Parses a markdown document with optional YAML-style front matter.
 * @param {string} source
 * @returns {{frontMatter: Record<string, unknown>, body: string}}
 */
function parseFrontMatter(source) {
  const normalized = normalizeNewlines(source);
  const lines = normalized.split("\n");

  if (lines[0]?.trim() !== "---") {
    return {
      frontMatter: {},
      body: normalized.replace(/^\s*\n/, ""),
    };
  }

  let endIndex = -1;
  for (let index = 1; index < lines.length; index++) {
    if (lines[index].trim() === "---") {
      endIndex = index;
      break;
    }
  }

  if (endIndex === -1) {
    return {
      frontMatter: {},
      body: normalized.replace(/^\s*\n/, ""),
    };
  }

  const frontMatterText = lines.slice(1, endIndex).join("\n");
  const body = lines.slice(endIndex + 1).join("\n").replace(/^\s*\n/, "");

  return {
    frontMatter: parseSimpleFrontMatter(frontMatterText),
    body,
  };
}

/**
 * Parses the small front matter subset used by the project markdown files.
 * @param {string} text
 * @returns {Record<string, unknown>}
 */
function parseSimpleFrontMatter(text) {
  const result = {};
  const lines = normalizeNewlines(text).split("\n");
  let currentArrayKey = null;
  let currentArray = null;

  const commitArray = () => {
    if (currentArrayKey) {
      result[currentArrayKey] = currentArray || [];
    }
    currentArrayKey = null;
    currentArray = null;
  };

  for (const rawLine of lines) {
    const trimmed = rawLine.trim();
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    const arrayItemMatch = rawLine.match(/^\s*-\s+(.*)$/);
    if (currentArray && arrayItemMatch) {
      currentArray.push(parseFrontMatterScalar(arrayItemMatch[1]));
      continue;
    }

    if (currentArray) {
      commitArray();
    }

    const keyMatch = rawLine.match(/^([A-Za-z0-9_-]+):(?:\s*(.*))?$/);
    if (!keyMatch) {
      continue;
    }

    const key = keyMatch[1];
    const value = keyMatch[2] ?? "";

    if (value === "") {
      currentArrayKey = key;
      currentArray = [];
      continue;
    }

    result[key] = parseFrontMatterScalar(value);
  }

  commitArray();
  return result;
}

/**
 * Parses a single front matter scalar value.
 * @param {string} value
 * @returns {string | number | boolean | null | Array<string | number | boolean | null>}
 */
function parseFrontMatterScalar(value) {
  const trimmed = value.trim();

  if (!trimmed.length) {
    return "";
  }

  if (trimmed.startsWith("[") && trimmed.endsWith("]")) {
    return parseInlineArray(trimmed.slice(1, -1));
  }

  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'"))
  ) {
    return trimmed.slice(1, -1);
  }

  if (trimmed === "true") {
    return true;
  }

  if (trimmed === "false") {
    return false;
  }

  if (trimmed === "null") {
    return null;
  }

  const numericValue = Number(trimmed);
  if (!Number.isNaN(numericValue) && trimmed === String(numericValue)) {
    return numericValue;
  }

  return trimmed;
}

/**
 * Parses a comma-separated inline array from front matter.
 * @param {string} value
 * @returns {Array<string | number | boolean | null>}
 */
function parseInlineArray(value) {
  if (!value.trim()) {
    return [];
  }

  return value
    .split(",")
    .map((entry) => parseFrontMatterScalar(entry))
    .filter((entry) => entry !== "");
}

/**
 * Extracts a required string from front matter.
 * @param {unknown} value
 * @param {string} filePath
 * @param {string} key
 * @returns {string}
 */
function readRequiredString(value, filePath, key) {
  const result = readOptionalString(value);
  if (!result) {
    throw new Error(`Missing required front matter "${key}" in ${filePath}`);
  }

  return result;
}

/**
 * Extracts a normalized optional string from front matter.
 * @param {unknown} value
 * @returns {string}
 */
function readOptionalString(value) {
  return typeof value === "string" && value.trim() ? value.trim() : "";
}

/**
 * Extracts a normalized string array from front matter.
 * @param {unknown} value
 * @returns {string[]}
 */
function readStringArray(value) {
  return Array.isArray(value)
    ? value
        .filter((entry) => typeof entry === "string")
        .map((entry) => entry.trim())
        .filter(Boolean)
    : [];
}

/**
 * Extracts the theme metadata object from a theme module source file.
 * @param {string} source
 * @param {string} filePath
 * @returns {{id: string, label: string, order: number}}
 */
function extractThemeMeta(source, filePath) {
  const metaMatch = source.match(/export\s+const\s+themeMeta\s*=\s*{([\s\S]*?)}\s*;/);
  if (!metaMatch) {
    throw new Error(`Could not parse themeMeta in ${filePath}`);
  }

  const metaBody = metaMatch[1];
  const id = readObjectString(metaBody, "id", filePath);
  const label = readObjectString(metaBody, "label", filePath);
  const order = readObjectNumber(metaBody, "order", filePath, 0);

  return { id, label, order };
}

/**
 * Extracts a string property from a JavaScript object literal body.
 * @param {string} body
 * @param {string} key
 * @param {string} filePath
 * @returns {string}
 */
function readObjectString(body, key, filePath) {
  const match = body.match(new RegExp(`\\b${key}\\s*:\\s*["']([^"']+)["']`));
  if (!match) {
    throw new Error(`Missing "${key}" in themeMeta for ${filePath}`);
  }

  return match[1].trim();
}

/**
 * Extracts a numeric property from a JavaScript object literal body.
 * @param {string} body
 * @param {string} key
 * @param {string} filePath
 * @param {number} [fallback=0]
 * @returns {number}
 */
function readObjectNumber(body, key, filePath, fallback = 0) {
  const match = body.match(new RegExp(`\\b${key}\\s*:\\s*([-+]?[0-9]+(?:\\.[0-9]+)?)`));
  if (!match) {
    return fallback;
  }

  const value = Number(match[1]);
  if (Number.isNaN(value)) {
    throw new Error(`Invalid numeric "${key}" in themeMeta for ${filePath}`);
  }

  return value;
}

/**
 * Serializes the generated project registry module.
 * @param {Array<{
 *   slug: string,
 *   title: string,
 *   summary: string,
 *   date: string,
 *   type: string,
 *   thumbnail: string,
 *   heroImage: string,
 *   heroAlt: string,
 *   tags: string[],
 *   markdownPath: string,
 * }>} projects
 * @returns {string}
 */
function serializeProjectIndex(projects) {
  const projectEntries = projects
    .map((project) => `${indentBlock(JSON.stringify(project, null, 2), 2)},`)
    .join("\n");

  return [
    GENERATED_HEADER,
    "",
    "export const projects = [",
    projectEntries,
    "];",
    "",
    "export const projectIndex = projects;",
    "",
    "/**",
    " * Returns the generated project entry for a slug.",
    " * @param {string} slug",
    " * @returns {(typeof projects)[number] | null}",
    " */",
    "export function getProjectBySlug(slug) {",
    "  return projects.find((project) => project.slug === slug) || null;",
    "}",
    "",
  ].join("\n");
}

/**
 * Serializes the generated theme registry module.
 * @param {Array<{
 *   fileName: string,
 *   importBase: string,
 *   meta: {id: string, label: string, order: number},
 * }>} themes
 * @returns {string}
 */
function serializeThemeRegistry(themes) {
  const imports = themes
    .map((theme) => {
      const metaAlias = `${theme.importBase}Meta`;
      const createAlias = `create${toPascalIdentifier(theme.importBase)}`;
      return `import { createTheme as ${createAlias}, themeMeta as ${metaAlias} } from "../themes/${theme.fileName}";`;
    })
    .join("\n");

  const themeEntries = themes
    .map((theme) => {
      const metaAlias = `${theme.importBase}Meta`;
      const createAlias = `create${toPascalIdentifier(theme.importBase)}`;
      return [
        "  {",
        `    ...${metaAlias},`,
        `    displayName: ${metaAlias}.label,`,
        `    createTheme: ${createAlias},`,
        "  },",
      ].join("\n");
    })
    .join("\n");

  return [
    GENERATED_HEADER,
    "",
    imports,
    "",
    "export const themeList = [",
    themeEntries,
    "];",
    "",
    "export const themes = Object.fromEntries(",
    "  themeList.map((theme) => [theme.id, theme]),",
    ");",
    "",
    "/**",
    " * Returns the generated theme entry for an id.",
    " * @param {string} themeId",
    " * @returns {(typeof themeList)[number] | null}",
    " */",
    "export function getThemeById(themeId) {",
    "  return themes[themeId] || null;",
    "}",
    "",
  ].join("\n");
}

/**
 * Writes a file only when the contents have changed.
 * @param {string} filePath
 * @param {string} contents
 */
function writeFileIfChanged(filePath, contents) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });

  if (fs.existsSync(filePath)) {
    const existing = fs.readFileSync(filePath, "utf8");
    if (existing === contents) {
      return;
    }
  }

  fs.writeFileSync(filePath, contents, "utf8");
}

/**
 * Ensures a list of values is unique.
 * @param {string[]} values
 * @param {string} label
 */
function assertNoDuplicateValues(values, label) {
  const seen = new Set();
  for (const value of values) {
    if (seen.has(value)) {
      throw new Error(`Duplicate ${label} found: ${value}`);
    }
    seen.add(value);
  }
}

/**
 * Normalizes newlines to LF.
 * @param {string} value
 * @returns {string}
 */
function normalizeNewlines(value) {
  return value.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
}

/**
 * Converts a path to a POSIX-style string.
 * @param {string} value
 * @returns {string}
 */
function toPosix(value) {
  return value.split(path.sep).join("/");
}

/**
 * Produces an identifier-like base name for generated imports.
 * @param {string} value
 * @returns {string}
 */
function toIdentifierBase(value) {
  const stripped = value.replace(/[^A-Za-z0-9_$]/g, "");
  if (stripped && /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(stripped)) {
    return stripped;
  }

  const fallback = value
    .split(/[^A-Za-z0-9]+/)
    .filter(Boolean)
    .map((part, index) => {
      const lower = part.toLowerCase();
      if (index === 0) {
        return lower;
      }

      return lower.charAt(0).toUpperCase() + lower.slice(1);
    })
    .join("");

  if (!fallback) {
    return "theme";
  }

  return /^[A-Za-z_$]/.test(fallback) ? fallback : `_${fallback}`;
}

/**
 * Converts an identifier base to PascalCase.
 * @param {string} value
 * @returns {string}
 */
function toPascalIdentifier(value) {
  const base = toIdentifierBase(value);
  return base.charAt(0).toUpperCase() + base.slice(1);
}

/**
 * Indents every line of a text block by a given number of spaces.
 * @param {string} text
 * @param {number} spaces
 * @returns {string}
 */
function indentBlock(text, spaces) {
  const padding = " ".repeat(spaces);
  return text
    .split("\n")
    .map((line) => `${padding}${line}`)
    .join("\n");
}
